import './App.css';
import { useState, useEffect } from 'react';

function App() {
  const [todo, setTodo] = useState([]);
  const [newTodo, setNewTodo] = useState("");
  const [isDarkMode, setisDarkMode] = useState(false);

  const toggleDarkMode = () => setisDarkMode(!isDarkMode);

  // Load once
  useEffect(() => {
    const savedTodos = JSON.parse(localStorage.getItem("todos"));
    if (savedTodos) {
      setTodo(savedTodos);
    }
  }, []);

  // Save only when todos change and not empty
  useEffect(() => {
    if (todo.length > 0) {
      localStorage.setItem("todos", JSON.stringify(todo));
    }
  }, [todo]);

  const handleAdd = () => {
    if (!newTodo.trim()) return;
    setTodo(td => [...td, { text: newTodo, completed: false }]);
    setNewTodo("");
  };

  const toggleComplete = (index) => {
    setTodo(prev =>
      prev.map((t, i) =>
        i === index ? { ...t, completed: !t.completed } : t
      )
    );
  };

  const handleDelete = (index) => {
    setTodo(todo.filter((_, i) => i !== index));
  };

  return (
    <div className={`app ${isDarkMode ? 'dark' : 'light'}`}>
      <div className="wrap">
        <h1 className="logo">ToDo LIST</h1>
        <div className="add-tasks">
          <input
            type="text"
            value={newTodo}
            onChange={(e) => setNewTodo(e.target.value)}
            placeholder="Add your tasks..."
          />
          <button className="add" onClick={handleAdd}>ADD</button>
          <button className="mode" onClick={toggleDarkMode}>
            {isDarkMode ? "☀️" : "🌙"}
          </button>
        </div>
      </div>

      <div className="tasks">
        <h2>Goals to Achieve</h2>
        {todo.map((items, index) => (
          <div className="list-wrapper" key={index}>
            <input
              type="checkbox"
              checked={items.completed}
              onChange={() => toggleComplete(index)}
            />
            <div className="list">
              <span style={{ textDecoration: items.completed ? "line-through" : "none" }}>
                {items.text}
              </span>
              <div>
                <button onClick={() => handleDelete(index)}>Delete</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
